from google.cloud import dataproc_v1

client = dataproc_v1.BatchControllerClient(
    client_options={'api_endpoint': 'us-central1-dataproc.googleapis.com'}
)

# Lightning Engine is enabled via the runtime_config version.
batch = dataproc_v1.Batch(
    pyspark_batch=dataproc_v1.PySparkBatch(
        main_python_file_uri='gs://your-bucket/jobs/process_data.py',
    ),
    runtime_config=dataproc_v1.RuntimeConfig(
        version='2.3',  # Lightning Engine available in Dataproc 2.3+
        properties={
            'spark.dataproc.lightning.enabled': 'true',
        },
    ),
    environment_config=dataproc_v1.EnvironmentConfig(
        execution_config=dataproc_v1.ExecutionConfig(
            subnetwork_uri='projects/your-project/regions/us-central1/subnetworks/default',
        )
    ),
)

operation = client.create_batch(
    parent='projects/your-project-id/locations/us-central1',
    batch=batch,
    batch_id='lightning-batch-001',
)
result = operation.result()
print(f'Batch completed: {result.name}')
